sys_script_include.script:
var DocxUtil = Class.create();
DocxUtil.prototype = (function() {

    function getRelevantPart(html) {
        var index = html.indexOf("</style>");
        if (index >= 0) {
            return html.substring(index + 8);
        }
        return html;
    }

    function parseTag(xml, start) {
        var i = start;
        var found_start = false;
        while (i < xml.length) {
            if (xml[i++] == '<') {
                start = i;
                found_start = true;
                break;
            }
        }
        if (found_start == false) return null;
        // Closing-Tag?
        var isClosing = false;
        if (xml[i] === '/') {
            isClosing = true;
            i++;
        }
        // Tag-Name lesen
        var name = '';
        while (i < xml.length && /[^\s>/]/.test(xml[i])) {
            name += xml[i++];
        }
        // Bis zum Ende des Tags springen
        while (i < xml.length && xml[i] !== '>') {
            i++;
        }
        // Self-closing?
        var isSelfClosing = xml[i - 1] === '/';
        i++; // '>'

        var type = "open";
        if (isClosing) type = "close";
        else if (isSelfClosing) type = "self";

        return {
            "type": type,
            "name": name,
            "start": start,
            "end": i
        };
    }

    function parseText(xml, start) {
        var i = start;
        var text = '';

        while (i < xml.length && xml[i] !== '<') {
            if (xml[i] != "\r") { // Zeilenumbruch
                text += xml[i];
            }
            i++;
        }
        return {
            "text": text,
            "start": start,
            "end": i
        };
    }

	function addText(text, format, no_p) {
		var result = "";

		if(format[0] == "h1"){
			result += '<w:p w14:paraId="00000000" w14:textId="00000000" w:rsidR="00000000" w:rsidRPr="00000000" w:rsidRDefault="00000000" w:rsidP="00000000"><w:pPr><w:pStyle w:val="berschrift1"/></w:pPr><w:r><w:t>';
			result += text;
			result += '</w:t></w:r></w:p>';
		}else if(format[0] == "h2"){
			result += '<w:p w14:paraId="00000000" w14:textId="00000000" w:rsidR="00000000" w:rsidRPr="00000000" w:rsidRDefault="00000000" w:rsidP="00000000"><w:pPr><w:pStyle w:val="berschrift2"/></w:pPr><w:r><w:t>';
			result += text;
			result += '</w:t></w:r></w:p>';
		}else if(format[0] == "h3"){
			result += '<w:p w14:paraId="00000000" w14:textId="00000000" w:rsidR="00000000" w:rsidRPr="00000000" w:rsidRDefault="00000000" w:rsidP="00000000"><w:pPr><w:pStyle w:val="berschrift3"/></w:pPr><w:r><w:t>';
			result += text;
			result += '</w:t></w:r></w:p>';
		}else{
			result += '<w:p w14:paraId="00000000" w14:textId="00000000" w:rsidR="00000000" w:rsidRPr="00000000" w:rsidRDefault="00000000" w:rsidP="00000000"><w:r><w:t>'
			result += text;
			result += '</w:t></w:r></w:p>';
		}

		return result;
	}

    function processDocxXML(xmlString, target_sys_id) {
        var current = new GlideRecord("kb_template_how_to");
        if (!current.get(target_sys_id)) {
            gs.info("KNOWLEDGE ARTIKEL NICHT GEFUNDEN");
            return xmlString;
        }
        var html = current.getValue("kb_instructions");

        html = getRelevantPart(html);
        gs.info("\n" + html);

        var index = 0;
        var format = [];
        var text = "";
		var ersetzung = "";
        var newlinehandeled = true;
        while (true) {
            var tag = parseTag(html, index);

            if (tag != null) {
                if (tag["type"] == "open") {
                    format.push(tag["name"]);
                    if (tag["name"] == "p") {
                        newlinehandeled = false;
                    }
                } else if (tag["type"] == "close") {
                    format.pop();
                }
                index = tag["end"];
            } else {
                break;
            }
            text = parseText(html, tag["end"]);
            if (text["text"] != "") {
                if (format[0] == "p") {
                    if (newlinehandeled) {
                        gs.info(">" + text["text"] + "< als " + String(format) + " (ohne p) darstellen.");
						ersetzung += addText(text["text"], format, true);
                    } else {
                        gs.info(">" + text["text"] + "< als " + String(format) + " darstellen.");
						ersetzung += addText(text["text"], format, false);
                    }
                    newlinehandeled = true;
                } else {
                    gs.info(">" + text["text"] + "< als " + String(format) + " darstellen.");
					ersetzung += addText(text["text"], format, false);
                }
            }
        }
        return xmlString.replace('<===REPLACE HERE===>', ersetzung);
    }

    return {
        initialize: function() {},

        replaceText: function(target_sys_id) {
            var docx_attachment_id = "a66fff7783e84710916cf3a6feaad3d0";
            var new_file_name = "ARTIKEL.docx";
            var target_table = "kb_template_how_to";
            var xmlString = null;
            try {
                var Zip = new ZipUtil();
                // Unzip an attachment to a javascript object structure
                var archive = Zip.unzip(docx_attachment_id);
                // Look for the document.xml file and replace some text in it
                archive.files = archive.files.map(function(file) {
                    switch (file.file_name) {
                        case 'word/header1.xml':
                        case 'word/header2.xml':
                        case 'word/footer1.xml':
                        case 'word/footer2.xml':
                        case 'word/document.xml':
                            xmlString = Zip.charArrayToString(file.file_data);
                            xmlString = processDocxXML(xmlString, target_sys_id);
                            file.file_data = Zip.stringToCharArray(xmlString);
                            break;
                        case "word/settings.xml":
                            xmlString = Zip.charArrayToString(file.file_data);
                            file.file_data = Zip.stringToCharArray(xmlString);
                            break;
                        case "[Content_Types].xml":
                            xmlString = Zip.charArrayToString(file.file_data);
                            xmlString = xmlString.replace('.template.main', '.document.main');
                            file.file_data = Zip.stringToCharArray(xmlString);
                            break;
                        default:
                    }
                    return file;
                });

                // Turn the javascript object structure back into a zip file, attach it to a record on a table
                var mime = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
                if (target_table && target_sys_id && mime && new_file_name)
                    return Zip.rezip(archive, new_file_name, target_table, target_sys_id, mime);
                return Zip.rezipAsBytes(archive);

            } catch (e) {
                gs.error('DocX generation failed! ' + e + ":" + e.stack);
                throw e;
            }
        },

        /**
         * Get the CRC32 for a given string
         * @param {string} str 
         */
        crc32: function(str) {
            var crc = 0 ^ (-1);
            var crcTable = this.crcTable;

            for (var i = 0; i < str.length; i++) {
                crc = (crc >>> 8) ^ crcTable[(crc ^ str.charCodeAt(i)) & 0xFF];
            }

            return (crc ^ (-1)) >>> 0;
        },

        crcTable: function() {
            var c;
            var crcTable = [];
            for (var n = 0; n < 256; n++) {
                c = n;
                for (var k = 0; k < 8; k++) {
                    c = ((c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1));
                }
                crcTable[n] = c;
            }
            return crcTable;
        },

        type: 'DocxUtil'
    };
})();
